{{-- OG-image template per gemeente (1200x630). $name = gemeentenaam. --}}
<div style="width:1200px;height:630px;box-sizing:border-box;display:flex;flex-direction:column;justify-content:center;padding:90px;background:linear-gradient(135deg,#0f172a 0%,#134e4a 100%);color:#ffffff;font-family:'Instrument Sans',system-ui,-apple-system,sans-serif;">
    <div style="font-size:34px;font-weight:600;letter-spacing:.08em;color:#5eead4;text-transform:uppercase;">Volg je raad</div>
    <h1 style="font-size:104px;font-weight:800;line-height:1.02;margin:24px 0 0;max-width:1020px;">{{ $name }}</h1>
    <p style="font-size:38px;line-height:1.3;color:#cbd5e1;margin:32px 0 0;max-width:1020px;">Volg de gemeenteraad — elke vergadering samengevat in je inbox.</p>
</div>
